public class ActionEntityMapper(
    IDbContextFactory<ActionsDbContext> dbContextFactory,
    TranslationService translationService)
{
    public async Task<EntityMapperResult<ActionEntity>> MapAsync(
        List<SaveActionRequest> dtoList,
        Guid userId,
        Guid requestLanguageId,
        Guid defaultLanguageId,
        CancellationToken ct,
        ActionsDbContext? db = null)
    {
        var disposeDb = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            var result = new EntityMapperResult<ActionEntity>();
            var now = DateTime.UtcNow;

            foreach (var dto in dtoList)
            {
                var existing = dto.Id != Guid.Empty
                    ? await db.Actions.FindAsync([dto.Id], ct)
                    : null;

                if (existing is null)
                {
                    var entity = new ActionEntity
                    {
                        Id = Guid.CreateVersion7(),
                        Slug = dto.Slug,
                        ActionTypeCode = dto.ActionTypeCode.Trim().ToUpperInvariant(),
                        Status = (ActionStatus)dto.Status.Id,
                        IsActive = true,
                        CreatedDate = now,
                        CreatedById = userId,
                    };

                    translationService.AddOrUpdateEntityTranslation(
                        entity, requestLanguageId, dto.Name, dto.Description);

                    result.NewItems.Add(entity);
                }
                else
                {
                    existing.ActionTypeCode = dto.ActionTypeCode.Trim().ToUpperInvariant();
                    existing.Status = (ActionStatus)dto.Status.Id;
                    existing.UpdatedDate = now;
                    existing.UpdatedById = userId;

                    translationService.AddOrUpdateEntityTranslation(
                        existing, requestLanguageId, dto.Name, dto.Description);

                    result.UpdatedItems.Add(existing);
                }
            }

            return result;
        }
        finally
        {
            if (disposeDb) await db.DisposeAsync();
        }
    }
}

